const alerts = $node["ANALIZA - Sprawdź Problemy1"].json.alerty;
const db = $input.all().map(i => i.json);

// zamień DB na mapę dla szybkiego lookup
const map = {};
for (const row of db) {
  map[row.key] = row;
}

const noweAlerty = [];

for (const a of alerts) {
  const key = `${a.taskId}:${a.typ}`;

  const istnieje = map[key];

  if (!istnieje) {
    // NOWY ALERT
    noweAlerty.push({
      json: {
        key,
        taskId: a.taskId,
        typ: a.typ,
        lastSent: new Date().toISOString(),
        count: 1,
        data: a
      }
    });
  } else {
    // UPDATE – tylko jeśli chcesz ponowić po czasie
    const last = new Date(istnieje.lastSent);
    const now = new Date();
    const diffMin = (now - last) / 60000;

    let cooldown = 60; // default

    if (a.typ === 'spoznienie') cooldown = 240;
    if (a.typ === 'brak_raportu_pol') cooldown = 30;

    if (diffMin > cooldown) {
      noweAlerty.push({
        json: {
          key,
          taskId: a.taskId,
          typ: a.typ,
          lastSent: new Date().toISOString(),
          count: (istnieje.count || 1) + 1,
          data: a
        }
      });
    }
  }
}

return noweAlerty;
